// Compliant: Lock released on all paths using try-finally
public void Method(bool condition)
{
    Monitor.Enter(lockObj);
    try
    {
        if (condition)
        {
            return;
        }
        // Do work
    }
    finally
    {
        Monitor.Exit(lockObj); // Compliant
    }
}

// Compliant: Using lock statement ensures release on all paths
public void ProcessData()
{
    lock(lockObj) // Compliant
    {
        DoWork();
    }
}
